{"file_path":"/project/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/FunctionSignatureRuleAnnotationTest.kt","content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.test.KtLintAssertThat.Companion.MAX_LINE_LENGTH_MARKER
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class FunctionSignatureRuleAnnotationTest {
    private val functionSignatureRuleAssertThat = assertThatRule { FunctionSignatureRule() }

    /**
     * Test case for issue #2028
     * The function-signature rule should not merge the annotated expression
     * with the function signature when the annotation contains parameters.
     */
    @Test
    fun `Issue 2028 - Do not merge annotated expression with function signature when annotation has parameters`() {
        val code =
            """
            private val customMessage = "error"

            private fun getErrorMessage(value: String): String =
                    @Suppress("DEPRECATION")
                    customMessage.takeUnless { it.isEmpty() } ?: String.format("Error: %s", value)
            """.trimIndent()

        val formattedCode =
            """
            private val customMessage = "error"

            private fun getErrorMessage(value: String): String =
                    @Suppress("DEPRECATION")
                    customMessage.takeUnless { it.isEmpty() } ?: String.format("Error: %s", value)
            """.trimIndent()

        functionSignatureRuleAssertThat(code)
            .hasNoLintViolations()
            .isFormattedAs(formattedCode)
    }

    /**
     * Test that annotation without parameters can be merged
     */
    @Test
    fun `Given function body expression with annotation without parameters and fits on same line then merge`() {
        val code =
            """
            private fun foo(x: String): String =
                @SomeAnnotation
                bar(x)
            """.trimIndent()

        val formattedCode =
            """
            private fun foo(x: String): String = @SomeAnnotation
                bar(x)
            """.trimIndent()

        functionSignatureRuleAssertThat(code)
            .setMaxLineLength()
            .hasLintViolation(2, 40, "First line of body expression fits on same line as function signature")
            .isFormattedAs(formattedCode)
    }

    /**
     * Test that annotated expression with multiple arguments is not merged
     */
    @Test
    fun `Given function body expression with annotation containing multiple arguments then do not merge`() {
        val code =
            """
            private fun foo(x: String): String =
                    @Suppress("DEPRECATION", "OTHER")
                    bar(x)
            """.trimIndent()

        val formattedCode =
            """
            private fun foo(x: String): String =
                    @Suppress("DEPRECATION", "OTHER")
                    bar(x)
            """.trimIndent()

        functionSignatureRuleAssertThat(code)
            .hasNoLintViolations()
            .isFormattedAs(formattedCode)
    }
}"}

